config.script:
// jornada_binder (Jornada Fase B #760) — agente `script` (MACRO). Comportamento = ESTE arquivo (DADO).
//
// LATE-BINDING: quando uma entidade-alvo NASCE (evento de criação), liga o(s) slot(s) da
// jornada ativa do paciente que a AGUARDAM (contexto.espera) a essa entidade concreta,
// gravando `contexto.entidade_ref = {tipo, id}`. NÃO muda estado — quem fecha é o closer.
//
// Config-driven (tudo configurável): `config.mapa_criacao` mapeia event_type -> {entidade, id_campo}.
// O FILTRO do que cada slot aguarda vive no PRÓPRIO slot (contexto.espera.filtro), não aqui —
// assim um mesmo evento (ex.: agendamento_criado) só liga o slot cujo filtro bate (ex.: cirurgia).
//
// Injetados pelo runtime: event ({event_type, subject, payload_safe}), config, context, call(), log().
//   call(action, payload) -> { ok, status_code, body }  (só ações curadas; RBAC do SA é a jaula).

var subject = event.subject || {};
var safe = event.payload_safe || {};
var et = String(event.event_type || '');

var mapa = config.mapa_criacao || {};
var regra = mapa[et];
if (!regra) { log('binder: sem regra de criação p/ ' + et); return { skip: 'sem_regra', event_type: et }; }

var clienteId = subject.cliente_id;
if (!clienteId) { log('binder: evento sem cliente_id'); return { skip: 'sem_cliente' }; }
clienteId = String(clienteId);

// id da entidade que nasceu (fallback robusto p/ variação de nome no subject entre produtores).
var entId = subject[regra.id_campo] || subject[regra.entidade + '_id'] || subject.id;
if (!entId) { log('binder: sem id da entidade em ' + et); return { skip: 'sem_entidade_id' }; }
entId = String(entId);

// --- helpers -----------------------------------------------------------------
function unwrap(r) { var b = (r && r.body !== undefined) ? r.body : r; return (b && b.data !== undefined) ? b.data : b; }
function itens(d) { if (!d) return []; if (d.length !== undefined) return d; if (d.items) return d.items; return []; }
function primeiroId(d) { var a = itens(d); return (a[0] && a[0].id) ? String(a[0].id) : null; }
function vincJornada(t) {
  var vs = (t && t.vinculos) || [];
  for (var i = 0; i < vs.length; i++) { if (vs[i] && vs[i].tipo === 'jornada') return vs[i]; }
  return null;
}
// Igualdade simples sobre subject (preferencial) + payload_safe. Filtro null/ausente = passa.
function filtroBate(filtro, s, p) {
  if (!filtro) return true;
  for (var k in filtro) {
    if (!filtro.hasOwnProperty(k)) continue;
    var v = (s[k] !== undefined) ? s[k] : p[k];
    if (String(v) !== String(filtro[k])) return false;
  }
  return true;
}
// Ação CRÍTICA: TEM de suceder (senão vira false-success) — aborta o ramo (status=erro).
function callStrict(action, payload, oQue) {
  var r = call(action, payload);
  if (r && r.ok === false) throw new Error('ação crítica falhou (' + oQue + '): HTTP ' + r.status_code);
  return r;
}

// --- fluxo -------------------------------------------------------------------
var jornadaId = primeiroId(unwrap(call('buscar_jornada_ativa', { cliente_id: clienteId })));
if (!jornadaId) { log('binder: paciente sem jornada ativa'); return { skip: 'sem_jornada', cliente_id: clienteId }; }

var tarefas = itens(unwrap(call('listar_tarefas', { jornada_id: jornadaId })));
var ligados = [], conflitos = [];

for (var i = 0; i < tarefas.length; i++) {
  var t = tarefas[i];
  var v = vincJornada(t);
  if (!v) continue;
  var ctx = v.contexto || {};
  var espera = ctx.espera;
  if (!espera || espera.entidade !== regra.entidade) continue;   // slot não aguarda essa entidade
  if (!filtroBate(espera.filtro, subject, safe)) continue;       // filtro do slot não bate (ex.: não-cirurgia)

  if (ctx.entidade_ref && ctx.entidade_ref.id) {
    // Já ligado. Idempotente se for a MESMA entidade; conflito se for outra (nunca chuta).
    if (String(ctx.entidade_ref.id) !== entId) conflitos.push(t.id);
    continue;
  }

  // Merge não-destrutivo (o endpoint substitui o contexto inteiro → reenviar tudo).
  var novoCtx = {};
  for (var k in ctx) { if (ctx.hasOwnProperty(k)) novoCtx[k] = ctx[k]; }
  novoCtx.entidade_ref = { tipo: regra.entidade, id: entId };
  callStrict('set_contexto', { id: t.id, tipo: 'jornada', ref_id: String(v.ref_id), contexto: novoCtx }, 'set_contexto ' + t.id);
  ligados.push(t.id);
}

// Conflito → impedimento manual "precisa vincular" (decisão do handover: no ambíguo, nunca chuta).
for (var c = 0; c < conflitos.length; c++) {
  call('criar_impedimento', {
    id: conflitos[c],
    descricao: 'Late-binding: chegou uma nova ' + regra.entidade + ' (' + entId + '), mas este slot já está vinculado a outra. Vincular manualmente.'
  });
}

log('binder: jornada ' + jornadaId + ' — ' + ligados.length + ' slot(s) ligado(s) a ' + regra.entidade + ' ' + entId + ' (' + conflitos.length + ' conflito(s))');
return { jornada_id: jornadaId, entidade: regra.entidade, entidade_id: entId, ligados: ligados, conflitos: conflitos };

// jornada_closer (Jornada Fase B #760) — agente `script` (MACRO). Comportamento = ESTE arquivo (DADO).
//
// AUTO-CLOSE: quando uma entidade-alvo muda de estado (evento de status), aplica o desfecho no
// slot correspondente da jornada ativa do paciente (fecha = estado `done`). Config-driven:
// `config.mapa_desfecho` mapeia event_type -> { papel, id_campo, entidade, estado, filtro?, quando? }.
//   - `filtro`: igualdade obrigatória sobre subject/payload_safe (ex.: tipo_servico_id=cirurgia);
//   - `quando`: valor do campo tem de estar numa LISTA (ex.: status_para ∈ [aprovado, aprovado_parcial]).
// Acha o slot por `contexto.entidade_ref` (preciso, pós-binding) OU por `contexto.papel` (fallback,
// funciona mesmo sem o binder ter rodado). Idempotente: se já está no estado alvo, no-op.
//
// Injetados pelo runtime: event ({event_type, subject, payload_safe}), config, context, call(), log().

var subject = event.subject || {};
var safe = event.payload_safe || {};
var et = String(event.event_type || '');

var mapa = config.mapa_desfecho || {};
var regra = mapa[et];
if (!regra) { log('closer: sem regra de desfecho p/ ' + et); return { skip: 'sem_regra', event_type: et }; }

// --- guards ------------------------------------------------------------------
function valorDe(k, s, p) { return (s[k] !== undefined) ? s[k] : p[k]; }
function filtroBate(filtro, s, p) {
  if (!filtro) return true;
  for (var k in filtro) { if (!filtro.hasOwnProperty(k)) continue;
    if (String(valorDe(k, s, p)) !== String(filtro[k])) return false; }
  return true;
}
function quandoBate(quando, s, p) {
  if (!quando) return true;
  for (var k in quando) {
    if (!quando.hasOwnProperty(k)) continue;
    var v = valorDe(k, s, p);
    var permitidos = quando[k]; var ok = false;
    for (var i = 0; i < permitidos.length; i++) { if (String(permitidos[i]) === String(v)) { ok = true; break; } }
    if (!ok) return false;
  }
  return true;
}
if (!filtroBate(regra.filtro, subject, safe)) { log('closer: filtro não bate ' + et); return { skip: 'filtro', event_type: et }; }
if (!quandoBate(regra.quando, subject, safe)) { log('closer: `quando` não satisfeito ' + et); return { skip: 'quando', event_type: et }; }

var clienteId = subject.cliente_id;
if (!clienteId) { log('closer: evento sem cliente_id'); return { skip: 'sem_cliente' }; }
clienteId = String(clienteId);

var entId = regra.id_campo ? (subject[regra.id_campo] || (regra.entidade ? subject[regra.entidade + '_id'] : null)) : null;
if (entId) entId = String(entId);

// --- helpers -----------------------------------------------------------------
function unwrap(r) { var b = (r && r.body !== undefined) ? r.body : r; return (b && b.data !== undefined) ? b.data : b; }
function itens(d) { if (!d) return []; if (d.length !== undefined) return d; if (d.items) return d.items; return []; }
function primeiroId(d) { var a = itens(d); return (a[0] && a[0].id) ? String(a[0].id) : null; }
function vincJornada(t) { var vs = (t && t.vinculos) || []; for (var i = 0; i < vs.length; i++) { if (vs[i] && vs[i].tipo === 'jornada') return vs[i]; } return null; }
function callStrict(action, payload, oQue) { var r = call(action, payload); if (r && r.ok === false) throw new Error('ação crítica falhou (' + oQue + '): HTTP ' + r.status_code); return r; }

// Chama e devolve {ok, status, data} — distingue "falhou" de "vazio" (observabilidade).
function chamar(action, payload) {
  var r = call(action, payload);
  return { ok: !!(r && r.ok !== false), status: r ? r.status_code : null, data: unwrap(r), raw: r };
}

// --- fluxo -------------------------------------------------------------------
var jr = chamar('buscar_jornada_ativa', { cliente_id: clienteId });
var jornadaId = primeiroId(jr.data);
if (!jornadaId) {
  // Distingue: erro na chamada (rede/403/5xx) vs realmente sem jornada ativa (200 + vazio).
  var motivo = jr.ok ? 'sem_jornada' : 'erro_buscar_jornada';
  log('closer: ' + motivo + ' (http=' + jr.status + ')');
  return { skip: motivo, http_status: jr.status, ok: jr.ok, amostra: JSON.stringify(jr.data).slice(0, 300) };
}

var tl = chamar('listar_tarefas', { jornada_id: jornadaId });
if (!tl.ok) { log('closer: erro ao listar tarefas (http=' + tl.status + ')'); return { skip: 'erro_listar_tarefas', http_status: tl.status, jornada_id: jornadaId }; }
var tarefas = itens(tl.data);
var alvo = null;

// 1) Preciso: casa a entidade concreta ligada pelo binder (contexto.entidade_ref.id).
if (entId) {
  for (var i = 0; i < tarefas.length; i++) {
    var v = vincJornada(tarefas[i]); var ctx = (v && v.contexto) || {};
    if (ctx.entidade_ref && String(ctx.entidade_ref.id) === entId) { alvo = tarefas[i]; break; }
  }
}
// 2) Fallback: por papel (funciona antes do binding / p/ entidades sem ref no evento).
if (!alvo && regra.papel) {
  for (var j = 0; j < tarefas.length; j++) {
    var v2 = vincJornada(tarefas[j]); var ctx2 = (v2 && v2.contexto) || {};
    if (ctx2.papel === regra.papel) { alvo = tarefas[j]; break; }
  }
}
if (!alvo) { log('closer: nenhum slot p/ papel=' + regra.papel + ' ent=' + entId); return { skip: 'sem_slot', jornada_id: jornadaId }; }

var estadoAlvo = regra.estado || 'done';
if (alvo.estado === estadoAlvo || alvo.estado === 'done') {
  log('closer: slot ' + alvo.id + ' já em ' + alvo.estado + ' — no-op');
  return { noop: 'ja_no_estado', tarefa: alvo.id, estado: alvo.estado };
}

callStrict('mudar_estado', { id: alvo.id, estado: estadoAlvo, forcar: true }, 'mudar_estado ' + alvo.id);
call('recompute_fase', { id: jornadaId });   // best-effort: recomputa a fase macro após fechar
log('closer: slot ' + alvo.id + ' (papel=' + regra.papel + ') -> ' + estadoAlvo + ' na jornada ' + jornadaId);
return { fechada: alvo.id, papel: regra.papel, estado: estadoAlvo, jornada_id: jornadaId };
